import React from 'react';
import styles from './cart-subtotal.module.css';
import Title from '../../title';

const CartSubtotal = ({ title,}) => {
  return (
    <div className={styles.wrapper_subtotal}>
        <div className={styles.subtotal_top}>
            <Title level="h4" className={styles.subtotal_title}>Sub-total</Title>
            <p className={styles.subtotal_price}>$ 9.99</p>
        </div>
        <p className={styles.subtotal_VAT}>Tax and shipping cost will be calculated later</p>

    </div>
  )
}

export default CartSubtotal
